import Map from 'ol/Map';
import View from 'ol/View';
import XYZSource from 'ol/source/XYZ';
import Raster from 'ol/source/Raster';
import Point from 'ol/geom/Point';
import Image from 'ol/layer/Image';
import Feature from 'ol/Feature';
import { transformExtent, fromLonLat } from 'ol/proj';
import { Cluster, Vector as VectorSource } from 'ol/source';
import { Tile as TileLayer, Vector as VectorLayer } from 'ol/layer';
import { Circle as CircleStyle, Fill, Stroke, Style, Text, } from 'ol/style';
import { getCenter } from 'ol/extent';
var OpenLayerMap = /** @class */ (function () {
    function OpenLayerMap(element) {
        this.custerSource = new VectorSource;
        var tileEndpoint = element.dataset.tileendpoint;
        var grayScale = element.dataset.grayscale === 'true';
        var bbox = element.dataset.bbox.split(',').map(function (item) {
            return parseFloat(item);
        });
        var extent = transformExtent(bbox, 'EPSG:4326', 'EPSG:3857');
        this.map = new Map({
            layers: [
                this.buildMapLayer(tileEndpoint, grayScale),
                this.buildClusterLayer()
            ],
            target: element,
            view: new View({
                center: getCenter(extent),
                zoom: 14,
                minZoom: 0
            })
        });
    }
    OpenLayerMap.prototype.addMarkers = function (addressItems) {
        for (var i = 0; i < addressItems.items.length; i++) {
            var item = addressItems.items[i];
            var coodinates = fromLonLat([item.getLongitude(), item.getLatitude()]);
            this.custerSource.addFeature(new Feature(new Point(coodinates)));
        }
    };
    OpenLayerMap.prototype.buildClusterLayer = function () {
        var clusterSource = new Cluster({
            distance: 40,
            minDistance: 20,
            source: this.custerSource,
        });
        var styleCache = [];
        var clusters = new VectorLayer({
            source: clusterSource,
            style: function (feature) {
                var size = feature.get('features').length;
                var style = styleCache[size];
                if (!style) {
                    var style_1 = new Style({
                        image: new CircleStyle({
                            radius: 10,
                            stroke: new Stroke({
                                color: '#fff',
                            }),
                            fill: new Fill({
                                color: '#3399CC',
                            }),
                        }),
                        text: new Text({
                            text: size.toString(),
                            fill: new Fill({
                                color: '#fff',
                            }),
                        }),
                    });
                    styleCache[size] = style_1;
                }
                return style;
            },
        });
        return clusters;
    };
    OpenLayerMap.prototype.buildMapLayer = function (tileEndpoint, grayScale) {
        var osmSource = new XYZSource({
            attributions: '&#169; ' +
                '<a href="https://www.openstreetmap.org/copyright" target="_blank">OpenStreetMap</a> ' +
                'contributors.',
            urls: [
                tileEndpoint + '/?provider=osm&z={z}&x={x}&y={y}&s=a',
                tileEndpoint + '/?provider=osm&z={z}&x={x}&y={y}&s=b',
                tileEndpoint + '/?provider=osm&z={z}&x={x}&y={y}&s=c',
            ]
        });
        var mapLayer;
        if (!grayScale) {
            mapLayer = new TileLayer({
                source: osmSource,
            });
        }
        else {
            var rasterSource = new Raster({
                sources: [osmSource],
                operation: function (pixels, data) {
                    var pixel = pixels[0];
                    if (pixel.length >= 3) {
                        var r = pixel[0];
                        var g = pixel[1];
                        var b = pixel[2];
                        var v = 0.2126 * r + 0.7152 * g + 0.0722 * b;
                        pixel[0] = v; // Red
                        pixel[1] = v; // Green
                        pixel[2] = v; // Blue
                        //pixel[3] = 255;
                    }
                    return pixel;
                }
            });
            mapLayer = new Image({
                source: rasterSource
            });
        }
        return mapLayer;
    };
    return OpenLayerMap;
}());
export default OpenLayerMap;
